# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using UnityEngine.UI;
using System;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int maxHealth = 100;
    public int currency = 0;
    public int damage = 10;

    public void TakeDamage(int amount)
    {
        int finalDamage = Mathf.Max(0, amount);
        health = Mathf.Max(0, health - finalDamage);
    }

    public void Heal(int amount)
    {
        int finalHeal = Mathf.Max(0, amount);
        health = Mathf.Min(maxHealth, health + finalHeal);
    }

    public void AddCurrency(int amount)
    {
        currency = Mathf.Max(0, currency + Mathf.Max(0, amount));
    }

    public bool SpendCurrency(int amount)
    {
        amount = Mathf.Max(0, amount);
        if (currency < amount) return false;
        currency -= amount;
        return true;
    }

    public void IncreaseDamage(int amount)
    {
        damage = Mathf.Max(0, damage + Mathf.Max(0, amount));
    }
}

public class ShopItem : MonoBehaviour
{
    public string itemName = "Item";
    public int basePrice = 100;
    public int priceMultiplier = 1;
    public int damageBonus = 0;
    public int healthBonus = 0;

    public int GetPrice()
    {
        return Mathf.Max(0, basePrice * Mathf.Max(1, priceMultiplier));
    }

    public bool Purchase(PlayerStats player)
    {
        if (player == null) return false;

        int price = GetPrice();
        if (!player.SpendCurrency(price)) return false;

        if (damageBonus != 0) player.IncreaseDamage(damageBonus);
        if (healthBonus != 0)
        {
            player.maxHealth = Mathf.Max(1, player.maxHealth + healthBonus);
            player.health = Mathf.Min(player.maxHealth, player.health + healthBonus);
        }

        return true;
    }
}

public class DamageCalculator : MonoBehaviour
{
    public PlayerStats player;
    public int enemyDefense = 0;
    public float criticalChance = 0.1f;
    public float criticalMultiplier = 2f;

    public int CalculateDamage()
    {
        if (player == null) return 0;

        int baseDamage = Mathf.Max(0, player.damage);
        int reducedDamage = Mathf.Max(0, baseDamage - Mathf.Max(0, enemyDefense));

        bool critical = UnityEngine.Random.value < Mathf.Clamp01(criticalChance);
        if (critical)
        {
            reducedDamage = Mathf.RoundToInt(reducedDamage * Mathf.Max(1f, criticalMultiplier));
        }

        return reducedDamage;
    }

    public void DealDamageToTarget(PlayerStats target)
    {
        if (target == null) return;
        target.TakeDamage(CalculateDamage());
    }
}

public class ShopUI : MonoBehaviour
{
    public PlayerStats player;
    public ShopItem selectedItem;
    public Text currencyText;
    public Text healthText;
    public Text damageText;
    public Text priceText;
    public Button buyButton;

    private void Update()
    {
        if (player != null)
        {
            if (currencyText != null) currencyText.text = "Currency: " + player.currency;
            if (healthText != null) healthText.text = "Health: " + player.health + "/" + player.maxHealth;
            if (damageText != null) damageText.text = "Damage: " + player.damage;
        }

        if (selectedItem != null && priceText != null)
        {
            priceText.text = "Price: " + selectedItem.GetPrice();
        }

        if (buyButton != null)
        {
            buyButton.interactable = player != null && selectedItem != null && player.currency >= selectedItem.GetPrice();
        }
    }

    public void SelectItem(ShopItem item)
    {
        selectedItem = item;
    }

    public void BuySelectedItem()
    {
        if (player == null || selectedItem == null) return;
        selectedItem.Purchase(player);
    }
}

public class CurrencyReward : MonoBehaviour
{
    public PlayerStats player;
    public int rewardAmount = 10;

    public void GrantReward()
    {
        if (player != null)
        {
            player.AddCurrency(rewardAmount);
        }
    }
}